console.log("正在编辑博客类型，timelineId = "+timelineId);layui.use(["form","layer","util"],function(){let form=layui.form;let layer=layui.layer;let util=layui.util;let timeline;if(timelineId){form.verify({content:function(b,a){let contentRex=/^[\w\W\s\u4e00-\u9fcc]{2,255}$/;if(!contentRex.test(b)){return"内容只能为2-255个字符"}}});$.ajax({url:"/timeline/"+timelineId,method:"GET",dataType:"json",success:function(a){if(a.request==="success"&&a.status===200&&a.data){timeline=a.data[0];form.val("form-timeline",{id:timeline.id,content:timeline.content,pushDate:util.toDateString(timeline.pushDate,"yyyy-MM-dd")});form.render()}else{layer.msg(a.message+", 错误码: "+a.status,{icon:2})}},error:function(a){if(a){layer.msg(a)}else{layer.msg("请求错误，请检查网络",{icon:2})}}});form.on("submit(form-timeline-submit)",function(a){let timeline=a.field;layer.confirm("确认提交？",{btn:["确认","取消"]},function(b){$.ajax({url:"/timeline/"+timelineId,data:{content:timeline.content,pushDate:timeline.pushDate},method:"PUT",dateType:"json",success:function(c){if(c.request==="success"&&c.status===200){layer.msg(c.message,{icon:1})}else{layer.msg(c.message+", 错误码: "+c.status,{icon:2})}},error:function(c){if(c){layer.msg(c)}else{layer.msg("请求错误，请检查网络",{icon:2})}}});layer.close(b)});return false})}else{layer.msg("参数错误",{icon:2})}});